def validate_item(item):
    if "price" not in item or "quantity" not in item:
        return False
    if item["price"] <= 0 or item["quantity"] <= 0:
        return False
    return True

def calculate_total(items):
    total = 0
    for item in items:
        total += item["price"] * item["quantity"]
    return total

def process_order(order):
    if "items" not in order:
        print("Order contains no items.")
        return

    for item in order["items"]:
        if not validate_item(item):
            print(f"Invalid item in order: {item}")
            return

    total_price = calculate_total(order["items"])
    print(f"Total order price: ${total_price:.2f}")

if __name__ == "__main__":
    sample_order = {
        "items": [
            {"price": 10.0, "quantity": 2},
            {"price": 5.5, "quantity": 1},
        ]
    }
    process_order(sample_order)

    invalid_order = {
        "items": [
            {"price": 10.0, "quantity": 2},
            {"price": -5.5, "quantity": 1},
        ]
    }
    process_order(invalid_order)

